   184→	}
   185→
   186→	if r.regexpType == regexpTypeQuery {
   187→		return r.matchQueryString(req)
   188→	}
   189→	path := req.URL.Path
   190→	if r.options.useEncodedPath {
   191→		path = req.URL.EscapedPath()
   192→	}
